class User(db.Model):
    """Simple user model for MVP."""
    __tablename__ = 'users'

    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(255), unique=True, nullable=False, index=True)
    password_hash = db.Column(db.String(255), nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

    def __repr__(self):
        return f'<User {self.email}>'


class PasswordResetToken(db.Model):
    """Stores hashed password reset tokens."""
    __tablename__ = 'password_reset_tokens'

    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(255), nullable=False, index=True)
    token_hash = db.Column(db.String(64), nullable=False, unique=True, index=True)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)
    expires_at = db.Column(db.DateTime, nullable=False)
    used = db.Column(db.Boolean, default=False)

    def is_expired(self):
        return datetime.utcnow() > self.expires_at

    def __repr__(self):
        return f'<PasswordResetToken {self.email}>'


def hash_token(token):
    """Hash a token using SHA-256 for secure storage."""
    return hashlib.sha256(token.encode('utf-8')).hexdigest()


def generate_reset_token():
    """Generate a cryptographically secure random token."""
    return secrets.token_urlsafe(48)


def hash_password(password):
    """Simple password hashing for MVP. Use bcrypt/argon2 in production."""
    salt = secrets.token_hex(16)
    pw_hash = hashlib.sha256(f"{salt}{password}".encode()).hexdigest()
    return f"{salt}${pw_hash}"


def verify_password(stored_hash, password):
    """Verify password against stored hash."""
    salt, pw_hash = stored_hash.split('$')
    return hashlib.sha256(f"{salt}{password}".encode()).hexdigest() == pw_hash


def send_reset_email(email, token):
    """Send password reset email. Returns True on success, False on failure."""
    reset_url = f"{app.config['FRONTEND_URL']}/reset-password?token={token}"

    msg = MIMEMultipart('alternative')
    msg['Subject'] = 'Password Reset Request'
    msg['From'] = app.config['MAIL_FROM']
    msg['To'] = email

    text_body = f"""
You requested a password reset.

Click the link below to reset your password:
{reset_url}

This link will expire in {app.config['RESET_TOKEN_EXPIRY_MINUTES']} minutes.

If you did not request this reset, please ignore this email.
"""

    html_body = f"""
<html>
<body>
    <h2>Password Reset Request</h2>
    <p>You requested a password reset.</p>
    <p>Click the link below to reset your password:</p>
    <p><a href="{reset_url}">Reset Password</a></p>
    <p>This link will expire in {app.config['RESET_TOKEN_EXPIRY_MINUTES']} minutes.</p>
    <p><em>If you did not request this reset, please ignore this email.</em></p>
</body>
</html>
"""

    msg.attach(MIMEText(text_body, 'plain'))
    msg.attach(MIMEText(html_body, 'html'))

    try:
        server = smtplib.SMTP(app.config['MAIL_SERVER'], app.config['MAIL_PORT'])
        server.starttls()
        if app.config['MAIL_USERNAME'] and app.config['MAIL_PASSWORD']:
            server.login(app.config['MAIL_USERNAME'], app.config['MAIL_PASSWORD'])
        server.sendmail(app.config['MAIL_FROM'], email, msg.as_string())
        server.quit()
        return True
    except Exception as e:
        app.logger.error(f"Failed to send reset email: {e}")
        return False


def invalidate_existing_tokens(email):
    """Invalidate all existing unused tokens for a given email."""
    PasswordResetToken.query.filter_by(
        email=email.lower().strip(),
        used=False
    ).update({'used': True})
    db.session.commit()


def constant_time_response():
    """
    Add a small artificial delay to make timing attacks harder.
    This helps prevent email enumeration via response timing.
    """
    import random
    time.sleep(random.uniform(0.1, 0.3))


# --- API Endpoints ---

@app.route('/api/password-reset/request', methods=['POST'])
@limiter.limit("5 per minute")  # Strict rate limit on reset requests
@limiter.limit("10 per hour")
def request_password_reset():
    """
    Request a password reset link.
    
    Anti-enumeration: Always returns the same response regardless of whether
    the email exists in the database. This prevents attackers from discovering
    valid email addresses.
    """
    data = request.get_json()

    if not data or 'email' not in data:
        return jsonify({
            'message': 'Email is required.'
        }), 400

    email = data['email'].lower().strip()

    # Basic email format validation
    if not email or '@' not in email or '.' not in email.split('@')[-1]:
        return jsonify({
            'message': 'Invalid email format.'
        }), 400

    # Generic success message - ALWAYS returned regardless of email existence
    generic_response = jsonify({
        'message': 'If an account with that email exists, a password reset link has been sent. Please check your inbox and spam folder.'
    })

    user = User.query.filter_by(email=email).first()

    if not user:
        # User doesn't exist - return same response to prevent enumeration
        constant_time_response()
        return generic_response, 200

    # Check for recent reset requests to prevent abuse (max 3 active tokens)
    recent_tokens = PasswordResetToken.query.filter(
        PasswordResetToken.email == email,
        PasswordResetToken.used == False,
        PasswordResetToken.expires_at > datetime.utcnow(),
        PasswordResetToken.created_at > datetime.utcnow() - timedelta(minutes=5)
    ).count()

    if recent_tokens >= 3:
        # Too many recent requests, but still return generic response
        constant_time_response()
        return generic_response, 200

    # Invalidate any existing tokens for this email
    invalidate_existing_tokens(email)

    # Generate new token
    raw_token = generate_reset_token()
    token_hashed = hash_token(raw_token)
    expiry = datetime.utcnow() + timedelta(minutes=app.config['RESET_TOKEN_EXPIRY_MINUTES'])

    # Store hashed token in database (never store raw token)
    reset_token = PasswordResetToken(
        email=email,
        token_hash=token_hashed,
        expires_at=expiry
    )
    db.session.add(reset_token)
    db.session.commit()

    # Send email with raw token (user needs it to reset)
    send_reset_email(email, raw_token)

    constant_time_response()
    return generic_response, 200


@app.route('/api/password-reset/validate', methods=['POST'])
@limiter.limit("10 per minute")
def validate_reset_token():
    """
    Validate a password reset token without consuming it.
    Useful for frontend to check if token is valid before showing reset form.
    """
    data = request.get_json()

    if not data or 'token' not in data:
        return jsonify({'valid': False, 'message': 'Token is required.'}), 400

    token = data['token']
    token_hashed = hash_token(token)

    reset_token = PasswordResetToken.query.filter_by(
        token_hash=token_hashed,
        used=False
    ).first()

    if not reset_token:
        return jsonify({'valid': False, 'message': 'Invalid or expired token.'}), 400

    if reset_token.is_expired():
        return jsonify({'valid': False, 'message': 'Token has expired.'}), 400

    return jsonify({'valid': True, 'message': 'Token is valid.'}), 200


@app.route('/api/password-reset/confirm', methods=['POST'])
@limiter.limit("5 per minute")  # Strict rate limit on confirmation
@limiter.limit("15 per hour")
def confirm_password_reset():
    """
    Confirm password reset with token and new password.
    """
    data = request.get_json()

    if not data:
        return jsonify({'message': 'Request body is required.'}), 400

    token = data.get('token')
    new_password = data.get('new_password')
    confirm_password = data.get('confirm_password')

    # Validate inputs
    if not token:
        return jsonify({'message': 'Token is required.'}), 400

    if not new_password:
        return jsonify({'message': 'New password is required.'}), 400

    if len(new_password) < 8:
        return jsonify({'message': 'Password must be at least 8 characters long.'}), 400

    if len(new_password) > 128:
        return jsonify({'message': 'Password must not exceed 128 characters.'}), 400

    if confirm_password and new_password != confirm_password:
        return jsonify({'message': 'Passwords do not match.'}), 400

    # Look up the hashed token
    token_hashed = hash_token(token)

    reset_token = PasswordResetToken.query.filter_by(
        token_hash=token_hashed,
        used=False
    ).first()

    if not reset_token:
        return jsonify({'message': 'Invalid or expired reset token.'}), 400

    if reset_token.is_expired():
        # Mark as used so it can't be retried
        reset_token.used = True
        db.session.commit()
        return jsonify({'message': 'Reset token has expired. Please request a new one.'}), 400

    # Find the user
    user = User.query.filter_by(email=reset_token.email).first()

    if not user:
        # Edge case: user was deleted between request and confirm
        reset_token.used = True
        db.session.commit()
        return jsonify({'message': 'Unable to reset password.'}), 400

    # Update password
    user.password_hash = hash_password(new_password)

    # Mark token as used
    reset_token.used = True

    # Invalidate all other tokens for this user
    PasswordResetToken.query.filter(
        PasswordResetToken.email == user.email,
        PasswordResetToken.id != reset_token.id,
        PasswordResetToken.used == False
    ).update({'used': True})

    db.session.commit()

    return jsonify({'message': 'Password has been reset successfully.'}), 200


